        Ok(serde_json::json!({ "ok": true }))
    }
}

// ── Parse helpers ─────────────────────────────────────────────────────────────

fn parse_contact(p: Value) -> Result<Contact, moltis_service_traits::ErrorShape> {
    use secrecy::Secret;

    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let name = p
        .get("name")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: name"))?
        .to_owned();
    let stage = p
        .get("stage")
        .and_then(|v| v.as_str())
        .unwrap_or("lead")
        .parse::<ContactStage>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let now = now_ms();
    Ok(Contact {
        id,
        name,
        source: p.get("source").and_then(|v| v.as_str()).map(ToOwned::to_owned),
        external_id: p
            .get("externalId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        email: p
            .get("email")
            .and_then(|v| v.as_str())
            .map(|s| Secret::new(s.to_owned())),
        phone: p
            .get("phone")
            .and_then(|v| v.as_str())
            .map(|s| Secret::new(s.to_owned())),
        stage,
        metadata: p
            .get("metadata")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({})),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_channel(p: Value) -> Result<ContactChannel, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let contact_id = p
        .get("contactId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: contactId"))?
        .to_owned();
    let channel_type = p
        .get("channelType")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: channelType"))?
        .to_owned();
    let channel_id = p
        .get("channelId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: channelId"))?
        .to_owned();
    let now = now_ms();
    Ok(ContactChannel {
        id,
        contact_id,
        channel_type,
        channel_id,
        display_name: p
            .get("displayName")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        verified: p
            .get("verified")
            .and_then(|v| v.as_bool())
            .unwrap_or(false),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_matter(p: Value) -> Result<Matter, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let title = p
        .get("title")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: title"))?
        .to_owned();
    let status = p
        .get("status")
        .and_then(|v| v.as_str())
        .unwrap_or("open")
        .parse::<MatterStatus>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let phase = p
        .get("phase")
        .and_then(|v| v.as_str())
        .unwrap_or("intake")
        .parse::<MatterPhase>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let practice_area = p
        .get("practiceArea")
        .and_then(|v| v.as_str())
        .unwrap_or("other")
        .parse::<PracticeArea>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let now = now_ms();
    Ok(Matter {
        id,
        contact_id: p
            .get("contactId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        title,
        description: p
            .get("description")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        status,
        phase,
        practice_area,
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_interaction(p: Value) -> Result<Interaction, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let contact_id = p
        .get("contactId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: contactId"))?
        .to_owned();
    let kind = p
        .get("kind")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: kind"))?
        .parse::<InteractionKind>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let summary = p
        .get("summary")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: summary"))?
        .to_owned();
    let now = now_ms();
    Ok(Interaction {
        id,
        contact_id,
        matter_id: p
            .get("matterId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        kind,
        summary,
        channel: p
            .get("channel")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn now_ms() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as u64
}

