//! Live CRM service backed by the SQLite store.
//!
//! [`LiveCrmService`] implements [`moltis_service_traits::CrmService`] by
//! delegating to [`moltis_crm::SqliteCrmStore`].  Each RPC method deserialises
//! its `serde_json::Value` params, calls the appropriate store operation, and
//! serialises the result back.
//!
//! PII fields (email, phone) are exposed in responses — callers reach this
//! service only through the auth-gated WebSocket layer.

use std::sync::Arc;

use async_trait::async_trait;
use moltis_crm::{
    Contact, ContactChannel, Interaction, Matter, SqliteCrmStore, store::CrmStore,
    types::{
        ContactStage, InteractionKind, MatterPhase, MatterStatus, PracticeArea,
    },
};
use moltis_service_traits::{CrmService, ServiceResult};
use secrecy::ExposeSecret;
use serde_json::Value;

/// Live CRM service backed by a SQLite store.
pub struct LiveCrmService {
    store: Arc<SqliteCrmStore>,
}

impl LiveCrmService {
    #[must_use]
    pub fn new(store: Arc<SqliteCrmStore>) -> Self {
        Self { store }
    }
}

// ── Serialisation helpers ─────────────────────────────────────────────────────

fn contact_to_json(c: Contact) -> Value {
    use secrecy::ExposeSecret;
    serde_json::json!({
        "id":         c.id,
        "name":       c.name,
        "source":     c.source,
        "externalId": c.external_id,
        "email":      c.email.as_ref().map(|s| s.expose_secret()),
        "phone":      c.phone.as_ref().map(|s| s.expose_secret()),
        "stage":      c.stage.as_str(),
        "metadata":   c.metadata,
        "createdAt":  c.created_at,
        "updatedAt":  c.updated_at,
    })
}

fn channel_to_json(ch: ContactChannel) -> Value {
    serde_json::json!({
        "id":          ch.id,
        "contactId":   ch.contact_id,
        "channelType": ch.channel_type,
        "channelId":   ch.channel_id,
        "displayName": ch.display_name,
        "verified":    ch.verified,
        "createdAt":   ch.created_at,
        "updatedAt":   ch.updated_at,
    })
}

fn matter_to_json(m: Matter) -> Value {
    serde_json::json!({
        "id":           m.id,
        "contactId":    m.contact_id,
        "title":        m.title,
        "description":  m.description,
        "status":       m.status.as_str(),
        "phase":        m.phase.as_str(),
        "practiceArea": m.practice_area.as_str(),
        "createdAt":    m.created_at,
        "updatedAt":    m.updated_at,
    })
}

fn interaction_to_json(i: Interaction) -> Value {
    serde_json::json!({
        "id":        i.id,
        "contactId": i.contact_id,
        "matterId":  i.matter_id,
        "kind":      i.kind.as_str(),
        "summary":   i.summary,
        "channel":   i.channel,
        "createdAt": i.created_at,
        "updatedAt": i.updated_at,
    })
}

// ── CrmService impl ───────────────────────────────────────────────────────────

#[async_trait]
impl CrmService for LiveCrmService {
    // ── Contacts ──────────────────────────────────────────────────────────────

    async fn list_contacts(&self) -> ServiceResult {
        let contacts = self
            .store
            .list()
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        let json: Vec<Value> = contacts.into_iter().map(contact_to_json).collect();
        Ok(Value::Array(json))
    }

    async fn get_contact(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        let contact = self
            .store
            .get(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(contact.map(contact_to_json).unwrap_or(Value::Null))
    }

    async fn upsert_contact(&self, params: Value) -> ServiceResult {
        let contact = parse_contact(params)?;
        self.store
            .upsert(contact)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    async fn delete_contact(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        self.store
            .delete(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    // ── Contact channels ──────────────────────────────────────────────────────

    async fn list_channels(&self, params: Value) -> ServiceResult {
        let contact_id = params
            .get("contactId")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: contactId"))?;
        let channels = self
            .store
            .list_channels_for_contact(contact_id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        let json: Vec<Value> = channels.into_iter().map(channel_to_json).collect();
        Ok(Value::Array(json))
    }

    async fn upsert_channel(&self, params: Value) -> ServiceResult {
        let channel = parse_channel(params)?;
        self.store
            .upsert_channel(channel)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    async fn delete_channel(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        self.store
            .delete_channel(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    // ── Matters ───────────────────────────────────────────────────────────────

    async fn list_matters(&self) -> ServiceResult {
        let matters = self
            .store
            .list_matters()
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        let json: Vec<Value> = matters.into_iter().map(matter_to_json).collect();
        Ok(Value::Array(json))
    }

    async fn get_matter(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        let matter = self
            .store
            .get_matter(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(matter.map(matter_to_json).unwrap_or(Value::Null))
    }

    async fn upsert_matter(&self, params: Value) -> ServiceResult {
        let matter = parse_matter(params)?;
        self.store
            .upsert_matter(matter)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    async fn delete_matter(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        self.store
            .delete_matter(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    // ── Interactions ──────────────────────────────────────────────────────────

    async fn list_interactions(&self, params: Value) -> ServiceResult {
        if let Some(contact_id) = params.get("contactId").and_then(|v| v.as_str()) {
            let items = self
                .store
                .list_interactions_by_contact(contact_id)
                .await
                .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
            let json: Vec<Value> = items.into_iter().map(interaction_to_json).collect();
            return Ok(Value::Array(json));
        }
        if let Some(matter_id) = params.get("matterId").and_then(|v| v.as_str()) {
            let items = self
                .store
                .list_interactions_by_matter(matter_id)
                .await
                .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
            let json: Vec<Value> = items.into_iter().map(interaction_to_json).collect();
            return Ok(Value::Array(json));
        }
        Err(moltis_service_traits::ErrorShape::from(
            "list_interactions requires contactId or matterId",
        ))
    }

    async fn get_interaction(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        let item = self
            .store
            .get_interaction(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(item.map(interaction_to_json).unwrap_or(Value::Null))
    }

    async fn upsert_interaction(&self, params: Value) -> ServiceResult {
        let interaction = parse_interaction(params)?;
        self.store
            .upsert_interaction(interaction)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }

    async fn delete_interaction(&self, params: Value) -> ServiceResult {
        let id = params
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?;
        self.store
            .delete_interaction(id)
            .await
            .map_err(|e| moltis_service_traits::ErrorShape::from(e.to_string()))?;
        Ok(serde_json::json!({ "ok": true }))
    }
}

// ── Parse helpers ─────────────────────────────────────────────────────────────

fn parse_contact(p: Value) -> Result<Contact, moltis_service_traits::ErrorShape> {
    use secrecy::Secret;

    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let name = p
        .get("name")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: name"))?
        .to_owned();
    let stage = p
        .get("stage")
        .and_then(|v| v.as_str())
        .unwrap_or("lead")
        .parse::<ContactStage>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let now = now_ms();
    Ok(Contact {
        id,
        name,
        source: p.get("source").and_then(|v| v.as_str()).map(ToOwned::to_owned),
        external_id: p
            .get("externalId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        email: p
            .get("email")
            .and_then(|v| v.as_str())
            .map(|s| Secret::new(s.to_owned())),
        phone: p
            .get("phone")
            .and_then(|v| v.as_str())
            .map(|s| Secret::new(s.to_owned())),
        stage,
        metadata: p
            .get("metadata")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({})),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_channel(p: Value) -> Result<ContactChannel, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let contact_id = p
        .get("contactId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: contactId"))?
        .to_owned();
    let channel_type = p
        .get("channelType")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: channelType"))?
        .to_owned();
    let channel_id = p
        .get("channelId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: channelId"))?
        .to_owned();
    let now = now_ms();
    Ok(ContactChannel {
        id,
        contact_id,
        channel_type,
        channel_id,
        display_name: p
            .get("displayName")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        verified: p
            .get("verified")
            .and_then(|v| v.as_bool())
            .unwrap_or(false),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_matter(p: Value) -> Result<Matter, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let title = p
        .get("title")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: title"))?
        .to_owned();
    let status = p
        .get("status")
        .and_then(|v| v.as_str())
        .unwrap_or("open")
        .parse::<MatterStatus>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let phase = p
        .get("phase")
        .and_then(|v| v.as_str())
        .unwrap_or("intake")
        .parse::<MatterPhase>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let practice_area = p
        .get("practiceArea")
        .and_then(|v| v.as_str())
        .unwrap_or("other")
        .parse::<PracticeArea>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let now = now_ms();
    Ok(Matter {
        id,
        contact_id: p
            .get("contactId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        title,
        description: p
            .get("description")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        status,
        phase,
        practice_area,
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn parse_interaction(p: Value) -> Result<Interaction, moltis_service_traits::ErrorShape> {
    let id = p
        .get("id")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: id"))?
        .to_owned();
    let contact_id = p
        .get("contactId")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: contactId"))?
        .to_owned();
    let kind = p
        .get("kind")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: kind"))?
        .parse::<InteractionKind>()
        .map_err(|e| moltis_service_traits::ErrorShape::from(e))?;
    let summary = p
        .get("summary")
        .and_then(|v| v.as_str())
        .ok_or_else(|| moltis_service_traits::ErrorShape::from("missing field: summary"))?
        .to_owned();
    let now = now_ms();
    Ok(Interaction {
        id,
        contact_id,
        matter_id: p
            .get("matterId")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        kind,
        summary,
        channel: p
            .get("channel")
            .and_then(|v| v.as_str())
            .map(ToOwned::to_owned),
        created_at: p
            .get("createdAt")
            .and_then(|v| v.as_u64())
            .unwrap_or(now),
        updated_at: now,
    })
}

fn now_ms() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as u64
}

// ── Tests ─────────────────────────────────────────────────────────────────────

#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used)]
mod tests {
    use super::*;
    use moltis_crm::SqliteCrmStore;
    use sqlx::SqlitePool;

    async fn make_service() -> LiveCrmService {
        let pool = SqlitePool::connect("sqlite::memory:").await.unwrap();
        moltis_crm::run_migrations(&pool).await.unwrap();
        LiveCrmService::new(Arc::new(SqliteCrmStore::new(pool)))
    }

    // ── Contact CRUD ──────────────────────────────────────────────────────────

    #[tokio::test]
    async fn list_contacts_empty() {
        let svc = make_service().await;
        let result = svc.list_contacts().await.unwrap();
        assert_eq!(result, serde_json::json!([]));
    }

    #[tokio::test]
    async fn upsert_and_get_contact() {
        let svc = make_service().await;
        let id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({
            "id": id,
            "name": "Alice",
            "stage": "lead",
        }))
        .await
        .unwrap();
        let result = svc
            .get_contact(serde_json::json!({ "id": id }))
            .await
            .unwrap();
        assert_eq!(result["name"], "Alice");
        assert_eq!(result["stage"], "lead");
    }

    #[tokio::test]
    async fn list_contacts_returns_upserted() {
        let svc = make_service().await;
        let id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({ "id": id, "name": "Bob", "stage": "prospect" }))
            .await
            .unwrap();
        let result = svc.list_contacts().await.unwrap();
        let arr = result.as_array().unwrap();
        assert_eq!(arr.len(), 1);
        assert_eq!(arr[0]["name"], "Bob");
    }

    #[tokio::test]
    async fn delete_contact_removes_it() {
        let svc = make_service().await;
        let id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({ "id": id, "name": "Carol", "stage": "active" }))
            .await
            .unwrap();
        svc.delete_contact(serde_json::json!({ "id": id }))
            .await
            .unwrap();
        let result = svc
            .get_contact(serde_json::json!({ "id": id }))
            .await
            .unwrap();
        assert_eq!(result, Value::Null);
    }

    #[tokio::test]
    async fn get_contact_missing_id_errors() {
        let svc = make_service().await;
        assert!(svc.get_contact(serde_json::json!({})).await.is_err());
    }

    // ── Channels ──────────────────────────────────────────────────────────────

    #[tokio::test]
    async fn upsert_and_list_channels() {
        let svc = make_service().await;
        let contact_id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({
            "id": contact_id,
            "name": "Chan",
            "stage": "lead",
        }))
        .await
        .unwrap();
        let ch_id = uuid::Uuid::new_v4().to_string();
        svc.upsert_channel(serde_json::json!({
            "id": ch_id,
            "contactId": contact_id,
            "channelType": "telegram",
            "channelId": "tg-999",
        }))
        .await
        .unwrap();
        let result = svc
            .list_channels(serde_json::json!({ "contactId": contact_id }))
            .await
            .unwrap();
        let arr = result.as_array().unwrap();
        assert_eq!(arr.len(), 1);
        assert_eq!(arr[0]["channelType"], "telegram");
    }

    #[tokio::test]
    async fn delete_channel_removes_it() {
        let svc = make_service().await;
        let contact_id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({
            "id": contact_id,
            "name": "Del",
            "stage": "lead",
        }))
        .await
        .unwrap();
        let ch_id = uuid::Uuid::new_v4().to_string();
        svc.upsert_channel(serde_json::json!({
            "id": ch_id,
            "contactId": contact_id,
            "channelType": "slack",
            "channelId": "U-1",
        }))
        .await
        .unwrap();
        svc.delete_channel(serde_json::json!({ "id": ch_id }))
            .await
            .unwrap();
        let result = svc
            .list_channels(serde_json::json!({ "contactId": contact_id }))
            .await
            .unwrap();
        assert_eq!(result.as_array().unwrap().len(), 0);
    }

    // ── Matters ───────────────────────────────────────────────────────────────

    #[tokio::test]
    async fn upsert_and_get_matter() {
        let svc = make_service().await;
        let contact_id = uuid::Uuid::new_v4().to_string();
        svc.upsert_contact(serde_json::json!({
            "id": contact_id,
            "name": "MatterTest",
            "stage": "active",
        }))
        .await
        .unwrap();
        let mid = uuid::Uuid::new_v4().to_string();
