        let sessions_dir = tmp.path().join("sessions");
        std::fs::create_dir_all(&sessions_dir).unwrap();
        let session_store = Arc::new(SessionStore::new(sessions_dir));

        session_store
            .append(
                "smoke-session",
                &serde_json::json!({"role": "user", "content": "Hello from smoke test"}),
            )
