async fn health_query_returns_data() {
    let mock = MockDispatch::new();
    mock.set_response("health", json!({"ok": true, "connections": 3}));
    let (schema, _) = build_test_schema(mock.clone());

    let res = schema
        .execute(Request::new("{ health { ok connections } }"))
